int noise2(int x, int y)
{
    int tmp = hash[(y + SEED) % 256];
    return hash[(tmp + x) % 256];
}
float lin_inter(float x, float y, float s)
{
    return x + s * (y-x);
}
float smooth_inter(float x, float y, float s)
{
    return lin_inter(x, y, s * s * (3-2*s));
}
float noise2d(float x, float y)
{
    int x_int = x;
    int y_int = y;
    float x_frac = x - x_int;
    float y_frac = y - y_int;
    int s = noise2(x_int, y_int);
    int t = noise2(x_int+1, y_int);
    int u = noise2(x_int, y_int+1);
    int v = noise2(x_int+1, y_int+1);
    float low = smooth_inter(s, t, x_frac);
    float high = smooth_inter(u, v, x_frac);
    return smooth_inter(low, high, y_frac);
}
float perlin2d(float x, float y, float freq, int depth)
{
    float xa = x*freq;
    float ya = y*freq;
    float amp = 1.0;
    float fin = 0;
    float div = 0.0;

    int i;
    for(i=0; i<depth; i++)
    {
        div += 256 * amp;
        fin += noise2d(xa, ya) * amp;
        amp /= 2;
        xa *= 2;
        ya *= 2;
    }

    return fin/div;
}

int noise2I(int x, int y)
{
    int tmp = hash[(y/1000 + SEED) % 256];
    return hash[(tmp + x/1000) % 256];
}
int lin_interI(int x, int y, int s)
{
    return x + s * (y-x) / 1000;
}
int smooth_interI(int x, int y, int s)
{
    return lin_interI(x, y, s * s * (3000-2000*s/1000) / 1000000);
}
int noise2dI(int x, int y)
{
    int x_int = x/1000;
    int y_int = y/1000;

    x_int *= 1000;
    y_int *= 1000;

    int x_frac = x - x_int;
    int y_frac = y - y_int;

    int s = noise2I(x_int, y_int) * 1000;
    int t = noise2I(x_int+1000, y_int) * 1000;
    int u = noise2I(x_int, y_int+1000) * 1000;
    int v = noise2I(x_int+1000, y_int+1000) * 1000;

    int low = smooth_interI(s, t, x_frac);
    int high = smooth_interI(u, v, x_frac);

    return smooth_interI(low, high, y_frac);
}

int getHeight(int x, int z)
{
    int chunkX = x/width;
    int chunkZ = z/width;
    int posX = x%width;
    int posZ = z%width;

    int y = 0;
    for (int i = 0; i < height; i++)
	{
        if(blocks[chunkX+chunkZ*totalChunkWidth][posX+posZ*width+i*width*width] == 1)
        {
            y = i;
            break;
        }
    }
    return y;
}
int GetPerlin(int x, int z)
{
    int Y1 = perlin2d(x * 2, z * 2, 0.032, 1) * 20;
    int Y2 = perlin2d(x * 2, z * 2, 0.014, 1) * 70;
    int Y3 = perlin2d(x * 2, z * 2, 0.006, 1) * 48;

    return ((Y1 + Y2 + Y3) / 3) + terrainHeight;
}
int Perlin3D(int x, int y, int z) 
{
    int ab = noise2dI(x, y) / 256;
    int bc = noise2dI(y, z) / 256;
    int ac = noise2dI(x, z) / 256;

    int ba = noise2dI(y, x) / 256;
    int cb = noise2dI(z, y) / 256;
    int ca = noise2dI(z, x) / 256;

    int abc = ab + bc + ac + ba + cb + ca;

    return abc / 6;
}

// Function to generate a random number based on current seed
#define MULTIPLIER 1664525
#define INCREMENT 1013904223
#define MULTIPLIER_X 2654435761
#define MULTIPLIER_Y 32452843
#define MULTIPLIER_Z 2654435769

unsigned int generate_random(unsigned int seed, int range) {
    unsigned int a = 1103515245;
    unsigned int c = 12345;
    unsigned int m = 1U << 31;  // Modulus, typically a large prime or power of 2

    // Calculate the next pseudo-random number using LCG
    seed = (a * seed + c) % m;

    // Map the generated number to the specified range
    return seed % (unsigned int)range;
}
unsigned int generate_random1D(unsigned int seed, int range, int x) {
    int seed_ = seed + x * MULTIPLIER_X;

    int seedOut = (seed_ * MULTIPLIER + INCREMENT) % range;
    return seedOut;
}
unsigned int generate_random2D(unsigned int seed, int range, int x, int y) {
    unsigned int seed_ = seed + (x * MULTIPLIER_X * MULTIPLIER_Y) * (y * MULTIPLIER_Y * MULTIPLIER_Z);

    int seedOut = (seed_ * MULTIPLIER + INCREMENT) % range;
    return seedOut;
}
unsigned int generate_random2DO(unsigned int seed, int range, int x, int y) {
    int seed_ = seed;

    seed_ = seed + x * 31 + y * 71;

    int seedOut = (seed_ * MULTIPLIER + INCREMENT) % range;
    return seedOut;
}
unsigned int generate_random3D(unsigned int seed, int range, int x, int y, int z) {
    unsigned int seed_ = seed + (x * MULTIPLIER_X) * (y * MULTIPLIER_Y) * (z * MULTIPLIER_Z);

    unsigned int seedOut = (seed_ * MULTIPLIER + INCREMENT) % range;
    return seedOut;
}
unsigned int rotl(unsigned int value, int shift) {
    return (value << shift) | (value >> (32 - shift));
}
unsigned int trulyRandom2D(unsigned int seed, int range, int x, int y) {
    // XOR-shift scrambling
	seed = seed ^ (x * 2654435761u) ^ (y * 805306457u);
    x = x ^ 362437;
    y = y ^ 521288629;

    seed ^= (seed << 13);
    seed ^= (seed >> 17);
    seed ^= (seed << 5);

    x ^= rotl(seed, 7);
    y ^= rotl(x, 11);
    
    unsigned int random_number = (x * 1664525u + y * 1013904223u) ^ seed;
    
    return random_number % range;
}

void Quick_SortInt(int *arr, int left, int right) 
{
    if (left < right)
    {
        int pivot = PartitionInt(arr, left, right);

        if (pivot > 1)
        Quick_SortInt(arr, left, pivot - 1);

        if (pivot + 1 < right)
        Quick_SortInt(arr, pivot + 1, right);
    }
}
int PartitionInt(int *arr, int left, int right)
{
    int pivot = arr[left];

    while (true) 
    {
        while (arr[left] < pivot)
        left++;

        while (arr[right] > pivot)
        right--;

        if (left < right)
        {
            if (arr[left] == arr[right]) 
			return right;

            int temp = arr[left];
            arr[left] = arr[right];
            arr[right] = temp;
        }
        else 
        return right;
    }
}

//time operations
void deltaTimeCalculate()
{
    int deltaTimeOld = deltaTime;

    const int time2 = time1;
    time1 = RTC_GetTicks();
    deltaTime = time1 - time2;
    deltaTime /= 128;

    if(deltaTime > 1)
    deltaTime = deltaTimeOld;

    deltaTimeNoSlow = deltaTime;
    if(slow == true)
    deltaTime /= 10;
}

