                                            //if(blockTypes[currentBlockType].normal[blockRotation][i].x != 0)
                                            //brightness -= 2;
                                            //if(blockTypes[currentBlockType].normal[blockRotation][i].z != 0)
                                            //brightness -= 4;

                                            if(brightness < 0)
                                            brightness = 0;

                                            allObj[chunkIndex].brightnes[currentTriangleLength] = brightness;

                                            verticesIPCTemp[currentVerticeLength+0].x = (x + chunkX * width) * 10 + blockTypes[currentBlockType].vertices[blockRotation][blockTypes[currentBlockType].faces[i].x].x;
                                            verticesIPCTemp[currentVerticeLength+0].y = y * 10 +                    blockTypes[currentBlockType].vertices[blockRotation][blockTypes[currentBlockType].faces[i].x].y;
                                            verticesIPCTemp[currentVerticeLength+0].z = (z + chunkZ * width) * 10 + blockTypes[currentBlockType].vertices[blockRotation][blockTypes[currentBlockType].faces[i].x].z;

                                            verticesIPCTemp[currentVerticeLength+1].x = (x + chunkX * width) * 10 + blockTypes[currentBlockType].vertices[blockRotation][blockTypes[currentBlockType].faces[i].y].x;
                                            verticesIPCTemp[currentVerticeLength+1].y = y * 10 +                    blockTypes[currentBlockType].vertices[blockRotation][blockTypes[currentBlockType].faces[i].y].y;
                                            verticesIPCTemp[currentVerticeLength+1].z = (z + chunkZ * width) * 10 + blockTypes[currentBlockType].vertices[blockRotation][blockTypes[currentBlockType].faces[i].y].z;

                                            verticesIPCTemp[currentVerticeLength+2].x = (x + chunkX * width) * 10 + blockTypes[currentBlockType].vertices[blockRotation][blockTypes[currentBlockType].faces[i].z].x;
                                            verticesIPCTemp[currentVerticeLength+2].y = y * 10 +                    blockTypes[currentBlockType].vertices[blockRotation][blockTypes[currentBlockType].faces[i].z].y;
                                            verticesIPCTemp[currentVerticeLength+2].z = (z + chunkZ * width) * 10 + blockTypes[currentBlockType].vertices[blockRotation][blockTypes[currentBlockType].faces[i].z].z;

                                            verticesIPCTemp[currentVerticeLength+3].x = (x + chunkX * width) * 10 + blockTypes[currentBlockType].vertices[blockRotation][blockTypes[currentBlockType].faces[i].w].x;
                                            verticesIPCTemp[currentVerticeLength+3].y = y * 10 +                    blockTypes[currentBlockType].vertices[blockRotation][blockTypes[currentBlockType].faces[i].w].y;
                                            verticesIPCTemp[currentVerticeLength+3].z = (z + chunkZ * width) * 10 + blockTypes[currentBlockType].vertices[blockRotation][blockTypes[currentBlockType].faces[i].w].z;

